let anioActual = new Date().getFullYear();
let resultado = [];

for (let i = 5; i >= 0; i--) {
  let anio = (anioActual - i).toString();

  resultado.push({
    grd_siniest_anio: anio,
    grd_siniest_numSiniestros: 0,
    grd_siniest_valorReserva: 0,
    grd_siniest_gastosDefensa: 0,
    grd_siniest_valorPagado: 0,
    grd_siniest_TotalIncurrido: 0,
    grd_siniest_DescripcionSiniestro: ""
  });
}

//console.log("grd_siniestralidad", this.grd_siniestralidad);

