if (!Array.isArray(this.grd_siniestralidad)) return

this.grd_siniestralidad.forEach((row, index) => {
  const reserva = Number(row.grd_siniest_valorReserva || 0)
  const defensa = Number(row.grd_siniest_gastosDefensa || 0)
  const pagado  = Number(row.grd_siniest_valorPagado || 0)

  const total = reserva + defensa + pagado

  if (row.grd_siniest_TotalIncurrido !== total) {
    this.grd_siniestralidad[index].grd_siniest_TotalIncurrido = total
  }
})

return Number(this.grd_siniest_numSiniestros_1)
