const aniosRaw = [
  this.grd_siniest_numSiniestros_1,
  this.grd_siniest_numSiniestros_2,
  this.grd_siniest_numSiniestros_3,
  this.grd_siniest_numSiniestros_4,
  this.grd_siniest_numSiniestros_5,
  this.grd_siniest_numSiniestros_6
];

const cantidadAnios = Number(this.frm_valorRC_cantidadAnios) || 0;

const esSinSiniestro = (v) => {
  if (v === null || v === undefined) return true;
  if (typeof v === "string") {
    const t = v.trim();
    if (t === "") return true;
    if (!isNaN(t) && Number(t) === 0) return true;
    return false;
  }
  if (typeof v === "number" && v === 0) return true;
  return false;
};

const aniosSinSiniestros = aniosRaw.filter(v => esSinSiniestro(v)).length;

return Math.min(cantidadAnios, aniosSinSiniestros);

const esNoCero = (v) => {

  if (v === null || v === undefined) {
    return false;
  }

  const n = Number(typeof v === "string" ? v.trim() : v);

  const resultado = (!Number.isNaN(n) && n !== 0);

  return resultado;
};

const siniestralidadRaw = (this.frm_siniestralidad || "");

const siniestralidadSI = siniestralidadRaw
  .toString()
  .trim()
  .toUpperCase() === "SI";

const hayParConDatos = [1, 2, 3, 4, 5, 6].some(i => {
  const siniestros = this[`grd_siniest_numSiniestros_${i}`];
  const incurrido  = this[`grd_siniest_TotalIncurrido_${i}`];

  const r1 = esNoCero(siniestros);
  const r2 = esNoCero(incurrido);

  return r1 && r2;
});

const resultadoFinal = hayParConDatos ? "true" : "false";

return resultadoFinal;
